```class Solution {
public:
    int countOperations(int num1, int num2) {
        int result = 0;
        while (num1 >= num2) {
            num1 -= num2;
            result++;
        }
        while (num2 >= num1) {
            num2 -= num1;
            result++;
        }
        return result;
    }
};
```

